import{_ as l,o as r,c as t,ae as i}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"股市趋势技术分析圣经 - 第1章：股票交易的技术方法","description":"深入解读理查德·W·夏巴克经典著作，掌握股票技术分析的基础概念与方法论","frontmatter":{"title":"股市趋势技术分析圣经 - 第1章：股票交易的技术方法","description":"深入解读理查德·W·夏巴克经典著作，掌握股票技术分析的基础概念与方法论","date":"2026-04-18","author":"技术分析研习社","tags":["技术分析","股票图表","夏巴克","趋势分析","投资基础"],"category":"技术分析","cover":"/images/sta/chapter1-cover.jpg"},"headers":[],"relativePath":"posts/sta-chapter-1.md","filePath":"posts/sta-chapter-1.md"}'),e={name:"posts/sta-chapter-1.md"};function o(n,a,h,s,d,u){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="第1章-股票交易的技术方法" tabindex="-1">第1章：股票交易的技术方法 <a class="header-anchor" href="#第1章-股票交易的技术方法" aria-label="Permalink to &quot;第1章：股票交易的技术方法&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在股票投资的世界里，有人依靠基本面分析，研究公司的财务报表、行业前景和管理团队；也有人专注于技术分析，通过研究股价和成交量的历史数据来预测未来走势。理查德·W·夏巴克（Richard W. Schabacker）被誉为&quot;现代技术分析之父&quot;，他的著作《股市趋势技术分析圣经》为技术分析学派奠定了坚实的理论基础。</p><p>本章作为全书的开篇，将系统介绍股票技术分析的基本概念、核心方法论以及制图技术。无论你是刚刚踏入股市的新手，还是有一定经验的投资者，掌握这些基础知识都是迈向成功交易的必经之路。</p><h2 id="一、股票图的定义与核心价值" tabindex="-1">一、股票图的定义与核心价值 <a class="header-anchor" href="#一、股票图的定义与核心价值" aria-label="Permalink to &quot;一、股票图的定义与核心价值&quot;">​</a></h2><h3 id="_1-1-什么是股票图" tabindex="-1">1.1 什么是股票图？ <a class="header-anchor" href="#_1-1-什么是股票图" aria-label="Permalink to &quot;1.1 什么是股票图？&quot;">​</a></h3><p>夏巴克对股票图给出了一个简洁而全面的定义：<strong>&quot;股票图是对一只或一组股票交易历史的图记录。&quot;</strong></p><p>这个定义看似简单，却蕴含了技术分析的核心理念。设想一下，如果没有股票图，要了解某只股票过去一年的交易历史，你需要翻阅过去300天的报纸，或者收集整理300天的交易记录。而借助股票图，你只需要扫一眼，就能立刻获得那只股票过去一年每日交易的完整记录。</p><h3 id="_1-2-股票图的三大优势" tabindex="-1">1.2 股票图的三大优势 <a class="header-anchor" href="#_1-2-股票图的三大优势" aria-label="Permalink to &quot;1.2 股票图的三大优势&quot;">​</a></h3><h4 id="优势一-节省时间与精力" tabindex="-1">优势一：节省时间与精力 <a class="header-anchor" href="#优势一-节省时间与精力" aria-label="Permalink to &quot;优势一：节省时间与精力&quot;">​</a></h4><p>股票图帮助我们节省数天、数周、数月甚至数年的时间。就像报纸通过汇总每天的股票交易行情来节省投资者的时间一样，股票图将漫长的交易历史浓缩在一张图表中，让分析工作变得高效而便捷。</p><h4 id="优势二-完整记忆" tabindex="-1">优势二：完整记忆 <a class="header-anchor" href="#优势二-完整记忆" aria-label="Permalink to &quot;优势二：完整记忆&quot;">​</a></h4><p>人的记忆是有限的。假设你要研究某只股票过去一年的交易情况，当你研究到10月份的股价记录时，很难清楚地记得2月份的交易情况。股票图提供了&quot;完整记忆&quot;——一张黑白、永久、精准、完整的图形记录，让你能够一目了然地看到全貌。</p><h4 id="优势三-技术行为科学" tabindex="-1">优势三：技术行为科学 <a class="header-anchor" href="#优势三-技术行为科学" aria-label="Permalink to &quot;优势三：技术行为科学&quot;">​</a></h4><p>最重要的是，股票图引领我们进入一个新的科学领域——<strong>股票图技术行为（Technical Chart Action）的科学</strong>。通过对历史交易数据的图形化呈现，我们能够发现价格运动的规律、模式和特征，从而预测未来的价格趋势。</p><h2 id="二、技术分析-vs-基本面分析" tabindex="-1">二、技术分析 vs 基本面分析 <a class="header-anchor" href="#二、技术分析-vs-基本面分析" aria-label="Permalink to &quot;二、技术分析 vs 基本面分析&quot;">​</a></h2><h3 id="_2-1-技术分析的定义" tabindex="-1">2.1 技术分析的定义 <a class="header-anchor" href="#_2-1-技术分析的定义" aria-label="Permalink to &quot;2.1 技术分析的定义&quot;">​</a></h3><p>技术分析是一种排除了基本面等其他因素后，仅仅基于股票市场本身现象的分析方法。它关注的是：</p><ul><li>买卖双方的力量对比</li><li>供需关系的动态变化</li><li>市场参与者的心理和行为</li></ul><h3 id="_2-2-纯技术行为" tabindex="-1">2.2 纯技术行为 <a class="header-anchor" href="#_2-2-纯技术行为" aria-label="Permalink to &quot;2.2 纯技术行为&quot;">​</a></h3><p>从技术分析的角度，我们甚至不关心股票背后的公司是做什么的——无论是制造捕鼠器、锡罐、机车还是铝制牙签，无论公司属于工业、铁路还是公用事业行业。只要公司的股票还在公开证券交易所进行有序且积极的交易，股票图的制作和分析就没有本质区别。</p><p><strong>需要强调的是</strong>：这并不意味着基本面因素不重要。事实上，基本面因素非常重要，投资者应该加以慎重考虑。但是，股票图的图形本身与基本价值因素无关，而只与股票在公开市场的交易记录有关。</p><h3 id="_2-3-技术走势中反映出的基本面因素" tabindex="-1">2.3 技术走势中反映出的基本面因素 <a class="header-anchor" href="#_2-3-技术走势中反映出的基本面因素" aria-label="Permalink to &quot;2.3 技术走势中反映出的基本面因素&quot;">​</a></h3><p>有趣的是，股票图本身已经反映了基本面因素的影响。因为股票的每位多头与空头正是在基本面因素的影响下，做出交易该股票的决定。作为股票交易记录的图形表示，股票图已经包含了这些基本面因素的评估结果。</p><h3 id="_2-4-技术与基本面的矛盾" tabindex="-1">2.4 技术与基本面的矛盾 <a class="header-anchor" href="#_2-4-技术与基本面的矛盾" aria-label="Permalink to &quot;2.4 技术与基本面的矛盾&quot;">​</a></h3><p>当一只股票的基本面因素非常强，但由于弱的技术行为而使股价下跌时，我们不需要对这种矛盾感到困惑。可能的原因包括：</p><ul><li>投机者在数月前就买下了这只股票，等到此时有利的基本面因素出现时，卖出股票获利</li><li>内部人士或公司高级职员之前对本公司股票持仓太重，现在想要清掉</li><li>他们意识到基本面因素并没有新闻上宣称的那么好</li></ul><p><strong>关键是</strong>：当技术点位和基本面点位出现差别时，技术点位会胜出，因为它更贴近市场，而公开市场是股价变化的根本动力所在。</p><h2 id="三、股票价格趋势的三种类型" tabindex="-1">三、股票价格趋势的三种类型 <a class="header-anchor" href="#三、股票价格趋势的三种类型" aria-label="Permalink to &quot;三、股票价格趋势的三种类型&quot;">​</a></h2><p>在股票价格变动的历史中，我们发现有三种明确的运动趋势同时出现：</p><h3 id="_3-1-主要趋势-major-trend" tabindex="-1">3.1 主要趋势（Major Trend） <a class="header-anchor" href="#_3-1-主要趋势-major-trend" aria-label="Permalink to &quot;3.1 主要趋势（Major Trend）&quot;">​</a></h3><p>主要趋势指长期持续发生的价格变化趋势，一般持续一年以上，适于有大量资本金和耐心获取长线收入的投资者。</p><ul><li><strong>牛市</strong>：股价整体上涨的主要趋势</li><li><strong>熊市</strong>：股价整体下跌的主要趋势</li></ul><p>这种趋势改变频率很低，往往与经济周期紧密相关。基本经济规律对这种趋势的影响，多于供需因素的影响。</p><h3 id="_3-2-中期趋势-intermediate-trend" tabindex="-1">3.2 中期趋势（Intermediate Trend） <a class="header-anchor" href="#_3-2-中期趋势-intermediate-trend" aria-label="Permalink to &quot;3.2 中期趋势（Intermediate Trend）&quot;">​</a></h3><p>在每一次牛市和熊市过程中，存在许多被称为&quot;中期投机趋势&quot;的次级摆动，通常一年中发生数次。</p><ul><li>为擅长技术分析的交易员提供了极好的获利机会</li><li>获利总量可能远胜于长线投资者在主要趋势中的持有收益</li><li>需要比判断主要趋势更准确的预测方法</li></ul><h3 id="_3-3-微小趋势-minor-trend" tabindex="-1">3.3 微小趋势（Minor Trend） <a class="header-anchor" href="#_3-3-微小趋势-minor-trend" aria-label="Permalink to &quot;3.3 微小趋势（Minor Trend）&quot;">​</a></h3><p>组成每个中期趋势的众多短期价格运动被称为微小趋势或者即时趋势，一般只持续几周、几天、几小时甚至几分钟。</p><ul><li>只有最聪敏、最熟练的职业交易员才能从如此短的变化中持续获利</li><li>产生的佣金、税等费用与其收益往往不成比例</li><li>对新手心理的折磨较大，资金风险不断累积</li><li><strong>价值</strong>：在价格趋势方向尚不确定时给出早期线索，预示着新的中期趋势变化的开始</li></ul><h2 id="四、如何制作股票图" tabindex="-1">四、如何制作股票图 <a class="header-anchor" href="#四、如何制作股票图" aria-label="Permalink to &quot;四、如何制作股票图&quot;">​</a></h2><h3 id="_4-1-选择股票" tabindex="-1">4.1 选择股票 <a class="header-anchor" href="#_4-1-选择股票" aria-label="Permalink to &quot;4.1 选择股票&quot;">​</a></h3><p>对于初学者来说，一组15-20只股票的图形跟踪足以进行短期尝试。而对于非常希望研究股票图分析的交易人员来说，一组50-100只个股的图形跟踪也不算太多。</p><p><strong>选择原则</strong>：</p><ul><li>优先选择&quot;龙头股&quot;——比较活跃、比较重要的股票</li><li>选择有一定规模流通股的股票</li><li>包括你自己感兴趣或持有的股票</li></ul><h3 id="_4-2-制图用纸" tabindex="-1">4.2 制图用纸 <a class="header-anchor" href="#_4-2-制图用纸" aria-label="Permalink to &quot;4.2 制图用纸&quot;">​</a></h3><p>推荐使用坐标纸（co-ordinate paper），横轴和纵轴方向上的线越多越好。</p><p><strong>推荐规格</strong>：</p><ul><li>标准8.5英寸宽、11英寸长</li><li>水平方向和垂直方向每英寸分成20行</li><li>侧边有用于放入活页夹的圆孔</li></ul><h3 id="_4-3-构建坐标轴" tabindex="-1">4.3 构建坐标轴 <a class="header-anchor" href="#_4-3-构建坐标轴" aria-label="Permalink to &quot;4.3 构建坐标轴&quot;">​</a></h3><p><strong>价格轴（纵轴）</strong>：</p><ul><li>先回顾过去一年的股票价格范围并取均价，作为垂直方向位于中间的粗体线</li><li>如果股票价格为100，则垂直方向每条粗体显示的线表示5点</li><li>每条细线表示1/4点，每两条线的中线表示1/8点</li></ul><p><strong>时间轴（横轴）</strong>：</p><ul><li>每一条垂直线代表某一个交易日的结果</li><li>可以只标注周六、周一或任何你认为合适的规律日期</li><li><strong>重要原则</strong>：忽略纽交所闭市的日子，不要在股票图中留出空白垂直线</li></ul><h3 id="_4-4-绘制价格数据" tabindex="-1">4.4 绘制价格数据 <a class="header-anchor" href="#_4-4-绘制价格数据" aria-label="Permalink to &quot;4.4 绘制价格数据&quot;">​</a></h3><p>每天的报纸会提供所需数据——股票的最高价、最低价、收盘价和交易量。</p><p><strong>绘制方法</strong>：</p><ol><li>分别画出最高价和最低价</li><li>将两点垂直连接来表示当日股价变动范围</li><li>在垂直连接线上相应价格位置画出一条水平短线来代表收盘价</li></ol><h3 id="_4-5-绘制交易量" tabindex="-1">4.5 绘制交易量 <a class="header-anchor" href="#_4-5-绘制交易量" aria-label="Permalink to &quot;4.5 绘制交易量&quot;">​</a></h3><p>交易量是完整股票图中的另一个重要项目：</p><ul><li>一般用一条从基线出发的与价格线类似的垂直线来表示</li><li>任选一条顶部或底部的水平粗线代表零值</li><li>如果交易量较低，每条零值以上的粗线代表日交易20,000股</li><li>如果交易量较高，每条粗线代表100,000股</li></ul><h2 id="五、必要的时间范围" tabindex="-1">五、必要的时间范围 <a class="header-anchor" href="#五、必要的时间范围" aria-label="Permalink to &quot;五、必要的时间范围&quot;">​</a></h2><p>为了达到学习股票走势及技术操作的实用性目的：</p><ul><li><strong>日线图</strong>：至少应涵盖几周的数据，最好能涵盖几个月的数据</li><li><strong>周线图</strong>：帮助学生更好地判断股票的长期趋势与构形</li><li><strong>月线图</strong>：为长期的牛市或熊市价格变化提供紧凑的图形记录</li></ul><p><strong>总结</strong>：日线图和周线图是所有类型中最适合技术分析的股票图。</p><h2 id="六、开始前的警告" tabindex="-1">六、开始前的警告 <a class="header-anchor" href="#六、开始前的警告" aria-label="Permalink to &quot;六、开始前的警告&quot;">​</a></h2><h3 id="_6-1-小心-早期推定-陷阱" tabindex="-1">6.1 小心&quot;早期推定&quot;陷阱 <a class="header-anchor" href="#_6-1-小心-早期推定-陷阱" aria-label="Permalink to &quot;6.1 小心&quot;早期推定&quot;陷阱&quot;">​</a></h3><p>对于初学者来说，当他开始掌握股票图分析的基础原则，并第一次做出正确预测时，他所体会到的兴奋是无与伦比的。但接下来，当他意识到自己所做分析的巨大价值之后，学习的最大危险正潜伏在四周。</p><p>经历了最初几次预测的成功，学生很可能会：</p><ul><li>武断地将一个预测的结果错当成确定的事件</li><li>过分自信而过量交易</li><li>突然发现自己陷入了严重亏损的泥潭</li><li>对股票图预测变得优柔寡断、过分怀疑甚至痛苦地彻底失望</li></ul><h3 id="_6-2-想获利-无捷径" tabindex="-1">6.2 想获利，无捷径 <a class="header-anchor" href="#_6-2-想获利-无捷径" aria-label="Permalink to &quot;6.2 想获利，无捷径&quot;">​</a></h3><blockquote><p>&quot;股票市场中根本不存在获利的&#39;神奇公式&#39;。&quot;</p></blockquote><p>夏巴克在多年的市场分析与研究中，检验了许多投资&quot;体系&quot;和公式——不仅通过书面论证检验，也通过市场交易——没有发现任何可靠的捷径，没有一种体系能够取代对技术分析原则谨慎而持续的使用。</p><h3 id="_6-3-成功的股票图阅读心态" tabindex="-1">6.3 成功的股票图阅读心态 <a class="header-anchor" href="#_6-3-成功的股票图阅读心态" aria-label="Permalink to &quot;6.3 成功的股票图阅读心态&quot;">​</a></h3><p>成功的股票图阅读与交易技术需要：</p><ol><li><strong>提前发现例外情况的能力</strong></li><li><strong>对理论中的规则或走势保持一种潜意识里的怀疑态度</strong></li><li><strong>尽量避免或限制由于例外情况产生的亏损</strong></li></ol><p>正如华尔街上的一种说法：&quot;总是试图在最低谷买入或者在最高峰卖出的人，往往失大于得。&quot;</p><h2 id="七、本章总结" tabindex="-1">七、本章总结 <a class="header-anchor" href="#七、本章总结" aria-label="Permalink to &quot;七、本章总结&quot;">​</a></h2><p>本章我们学习了：</p><ol><li><strong>股票图的定义和价值</strong>——节省时间、提供完整记忆、引领技术行为科学</li><li><strong>技术分析与基本面分析的区别</strong>——技术分析关注市场本身的现象，基本面分析关注企业价值</li><li><strong>三种股票价格趋势</strong>——主要趋势、中期趋势、微小趋势</li><li><strong>股票图的制作方法</strong>——选择股票、制图用纸、构建坐标轴、绘制价格和交易量</li><li><strong>必要的学习心态</strong>——保持怀疑、避免过度自信、没有捷径</li></ol><p>在后续章节中，我们将深入学习各种重要的技术形态，包括反转形态、整理形态、成交量分析等核心内容。掌握这些基础知识后，你将能够更自信地解读股票图表，做出更明智的投资决策。</p><hr><p><strong>延伸阅读</strong>：</p><ul><li>第2章：重要的反转形态——头肩形态</li><li>第3章：重要的反转形态——圆形反转与三角形</li><li>第5章：成交量分析</li></ul><p><strong>免责声明</strong>：本文仅供学习交流使用，不构成投资建议。股市有风险，投资需谨慎。</p>',85)])])}const q=l(e,[["render",o]]);export{c as __pageData,q as default};
